from dataclasses import dataclass
from typing import Dict, List
from enum import Enum

class Severity(Enum):
    LOW = "low"
    MEDIUM = "medium"
    HIGH = "high"
    CRITICAL = "critical"

@dataclass
class Bottleneck:
    phase: str
    time_ms: float
    percentage: float
    severity: Severity
    recommendation: str

class BottleneckDetector:
    """Detect bottlenecks in pipeline execution."""

    def __init__(self, threshold_pct: float = 40.0):
        self.threshold_pct = threshold_pct
        self.phase_times: Dict[str, float] = {}

    def record(self, phase: str, time_ms: float):
        """Record timing for a phase."""
        self.phase_times[phase] = time_ms

    def _classify_severity(self, percentage: float) -> Severity:
        """Classify bottleneck severity."""
        if percentage > 70:
            return Severity.CRITICAL
        elif percentage > 55:
            return Severity.HIGH
        elif percentage > 40:
            return Severity.MEDIUM
        else:
            return Severity.LOW

    def _get_recommendation(self, phase: str) -> str:
        """Get recommendation for a bottleneck phase."""
        recommendations = {
            "transpilation": "Try lower optimization level or cache transpiled circuits",
            "execution": "Consider batch execution or check backend queue times",
            "queue_wait": "Schedule during off-peak hours or use alternative backends",
            "result_processing": "Use streaming processing or optimize data structures",
            "circuit_creation": "Use parameterized circuit templates"
        }
        return recommendations.get(phase, "Profile this phase in more detail")

    def detect(self) -> List[Bottleneck]:
        """Detect all bottlenecks above threshold."""
        if not self.phase_times:
            return []

        total_time = sum(self.phase_times.values())
        if total_time == 0:
            return []

        bottlenecks = []

        for phase, time_ms in self.phase_times.items():
            percentage = (time_ms / total_time) * 100

            if percentage >= self.threshold_pct:
                bottlenecks.append(Bottleneck(
                    phase=phase,
                    time_ms=time_ms,
                    percentage=percentage,
                    severity=self._classify_severity(percentage),
                    recommendation=self._get_recommendation(phase)
                ))

        # Sort by percentage descending
        return sorted(bottlenecks, key=lambda x: x.percentage, reverse=True)


# Test
if __name__ == "__main__":
    detector = BottleneckDetector(threshold_pct=30.0)

    detector.record("circuit_creation", 50)
    detector.record("transpilation", 350)
    detector.record("execution", 100)
    detector.record("result_processing", 25)

    print("Detected Bottlenecks:")
    print("-" * 50)
    bottlenecks = detector.detect()
    for bn in bottlenecks:
        print(f"{bn.phase}: {bn.percentage:.1f}% ({bn.severity.value})")
        print(f"  Time: {bn.time_ms} ms")
        print(f"  Recommendation: {bn.recommendation}\n")
